using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for Person: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing: TryGetTypeInfo checks availability, returns false if unavailable
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed);
Console.WriteLine($"\nTryGetTypeInfo(Person) => found={found}, type={probed?.Type.Name}");

// Now try a type that has no resolver (use options with NO resolver)
var emptyOptions = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // empty composite — resolves nothing
};

bool found2 = emptyOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probed2);
Console.WriteLine($"TryGetTypeInfo(Person) on empty resolver => found={found2}, info is null={probed2 is null}");

record Person(string Name, int Age);

